var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 나름 필요한 건 다 있네? 여기서 살림이라도 차렸어?","JPN":"へえ、結構色々揃ってるじゃん。ここで生活でも始める気？","ENG":"Wow, you have pretty much everything you need. Did you set up house here?","TWN":"哇，需要的東西都有耶？妳是在這裡成家了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"뭐래. 북방합의체의 정보를 넘겨주는 조건으로 잠시 머무르고 있을 뿐이거든?","JPN":"違うわよ。北方合意体の情報を渡す条件で、しばらく滞在してるだけ。","ENG":"What are you on about? I'm only staying for a bit in exchange for passing Northern Union intel.","TWN":"妳在說什麼？就只是以提供北方和議會的情報為條件暫時停留而已。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이런 시골에서 오래 머무를 생각은 없어. 마을 주민들과는 서로 이용하고 있을 뿐이야.","JPN":"こんな田舎に長居するつもりはないわ。村人とは、たまたま利害関係が一致しているに過ぎないし。","ENG":"I have no intention of lingering in a backwater village like this. The villagers and I are just using each other.","TWN":"我不想在這種鄉下停留太久，只不過是和村民互相利用而已。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데-. 장군이나 되던 인간이 뭣 때문에 배신을 해?","JPN":"でもさ～将軍までやってたのに何で裏切ったの？","ENG":"Then why would someone who used to be a general betray her side?","TWN":"但是–曾經當過將軍的人為什麼要背叛？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"너, 펠릭스의 말이라면 끔뻑 죽었잖아.","JPN":"あなた、フェリックスの命令なら何でも従ってたじゃない。","ENG":"You used to jump at Felix's every word.","TWN":"如果是緋莉克絲要妳死，妳馬上就去死了吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"<color=#ffd34c>예전</color>의 <color=#ffd34c>나</color>라면 그랬겠지.","JPN":"<color=#ffd34c>昔</color>の<color=#ffd34c>私</color>ならそうだったかもね。","ENG":"If it were the <color=#ffd34c>old</color> <color=#ffd34c>me</color>, maybe.","TWN":"換作是<color=#ffd34c>以前</color>的 <color=#ffd34c>我</color>應該會這樣。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만… 지금은 달라.","JPN":"でも……今は違う。","ENG":"But now it is different.","TWN":"但是…現在不一樣。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"믿기지 않겠지만 나도 혼란스럽다고.","JPN":"信じてくれないかもしれないけど、私だって混乱してるんだから。","ENG":"Believe it or not, I am confused too.","TWN":"雖然難以置信，但我也很混亂。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"쟤 갑자기 왜 저래? 뭐 아는 거 있어요?","JPN":"何か変なものでも食べたのかな？　何か知ってますか？","ENG":"Why is she acting like that all of a sudden? Do you know anything?","TWN":"她突然是怎麼了？是知道什麼嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"레, 레노어 언니가 최근 동면 캡슐에서 깨어났다는 이야기는 들었지만.","JPN":"レ、レノアさんがこの前冬眠カプセルから目覚めたという話は聞きました。","ENG":"I-I heard Ms. Lenore only recently woke up from the hibernation capsule.","TWN":"聽說蕾、蕾諾雅姐姐最近剛從冬眠艙甦醒。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"전 기본적으로 합의체 쪽에 가는 일이 드물어서… 얼굴을 본 건 엄청 오랜만이에요.","JPN":"でも私は合意体の方に行くことがあまりないから……顔を合わせたのはすごく久しぶりです。","ENG":"I rarely go to the Northern Union, so it has been ages since I saw her.","TWN":"我基本上很少去和議會那邊…所以真的很久沒見到她了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어라, 저는 이름으로 부르면서 쟤는 왜 언니예요?","JPN":"あれ、何で私は呼び捨てなのにあっちはさん付けなんですか？","ENG":"Oh? You call me by my name, but you call her with honorifics?","TWN":"咦？妳明明叫我名字，但為什麼叫她姐姐？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예, 예니카는 친구잖아요.","JPN":"イ、イェニカは友だちですから。","ENG":"B-because you're my friend.","TWN":"耶、耶妮卡是朋友嘛。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"친구 아니에요…?","JPN":"友だちじゃなかったですか……？","ENG":"Are we not friends...?","TWN":"不是朋友嗎…？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"친구, 친구 맞아요! 그러니까 뚝!!","JPN":"はい、友だち、友だちですよ！　だから泣かないで！！","ENG":"We're friends! We are! So stop crying!!","TWN":"是、是朋友沒錯！所以停！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"흥, 나도 내 사정 털어놓을 생각은 없어. 어차피 너희도 내 이야기엔 관심 없잖아?","JPN":"ふん、こっちだって、別に事情を察してほしいっていうわけじゃないわ。どうせ私の話に興味なんてないんでしょ？","ENG":"Hmph. I have no intention of spilling my story. You wouldn't care anyway.","TWN":"嗯，我也不打算說出自己的事，反正妳們也沒興趣吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너흴 도운데에는 그만한 이유가 있으니, 의심할 필요 없어.","JPN":"お前たちを助けたのも、ちゃんと理由があるんだから疑わなくていいわよ。","ENG":"I have my reasons for helping you, so there's no need to be suspicious.","TWN":"會幫助妳們是有原因的，所以不用懷疑。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하. 펠릭스가 우릴 감시하라 했구나?","JPN":"はは～ん、フェリックスが私たちを監視するように命令したんだ？","ENG":"A-ha. Felix told you to keep tabs on us, didn't she?","TWN":"啊哈，看來是緋莉克絲要妳監視我們啊？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그러니까 아니라고!","JPN":"だから違うって！","ENG":"I already told you that I'm out!","TWN":"我說不是！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너흴 도운 건, 내가 본 미래가 불길해서란 말이야!","JPN":"お前たちを助けたのは、私が見た未来が不吉だったからよ！","ENG":"I helped you because the future I saw was bad.","TWN":"我之所以會幫妳們，是因為看到不祥的未來！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"미래…? 오라클인지 뭔지 그거?","JPN":"未来……？　オラクルなんとかってやつ？","ENG":"The future? You mean that Oracle thing?","TWN":"未來…？是神諭還什麼的嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래. 근시안적인 부분을 제외하면 대부분의 미래가 어둡게 보여.","JPN":"ええ。すぐ先のことを除けば、ほとんどの未来が暗く見えるの。","ENG":"Yes. Aside from short-sighted blind spots, nearly every future looks bleak.","TWN":"沒錯，除了短視的部分之外，大部分的未來看起來都很黯淡。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"딱 한 번. 비슷한 경험을 한 기억이 있지만…….","JPN":"一度だけ、似たような経験をした覚えがあるけど……","ENG":"Only once. I remember a similar case...","TWN":"雖然我只記得有一次類似的經驗……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그건 오라클의 근원인 무녀의 핏줄이 명부신의 영혼을 받아들였기에 가능한 일이었어.","JPN":"その時はオラクルの根源である巫女の血統が、冥府の神の魂を受け入れたからできたのよ。","ENG":"That was possible because the priestess's blood accepted the Nether God's soul, which is the source of Oracle.","TWN":"但那是神諭來源巫女的血脈接收了冥府神的靈魂才可能辦到的事。"},"stage":{"bg":"NANAHARA2_05","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"명부신의 가능성이 산 자의 혼을 가려, 생명의 사념을 듣는 바람의 목소리에 영향을 끼친 거지.","JPN":"生者の魂が冥府の神の可能性に覆われて、命の思念を聞く風の声に影響を及ぼしたのよね。","ENG":"The Nether God's possibility sifted the living souls and affected the voice of wind that hears life's intent.","TWN":"冥府神的可能性會分辨活人的靈魂，對傾聽生命意念的風聲造成影響。"},"stage":{"bg":"NANAHARA2_05","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만 지금은 어떤 미래를 보든 똑같아.","JPN":"でも今はどんな未来を見ても同じ。","ENG":"But right now, no matter which future I look at, it is the same.","TWN":"但現在無論看什麼未來都一樣。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"곳곳에서 튀어나온 나무뿌리가 세상을 감싼 뒤, 오롯이 어둠만이 남은 세상…….","JPN":"あちこちから飛び出た木の根が世界を覆い隠し、やがては闇しか存在しない……","ENG":"Roots burst out everywhere and wrap the world, and only darkness remains...","TWN":"四處竄出的樹根包覆後，只剩下黑暗的世界……"},"stage":{"bg":"OMEN_LOTUS_01","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"내가 본 미래는 전부 그런 결과로 귀결됐어.","JPN":"私が見た未来はすべて、その結果に収束している。","ENG":"Every future I saw ends like that.","TWN":"我看見的未來全都是得出這樣的結果。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"클론에게 받은 기억을 더듬어봐도, 이런 적은 단한번도 없었다고.","JPN":"クローンから受け継いだ記憶をたどってみたけど、こんなことは一度としてなかったわ。","ENG":"Even combing through the memories I got from the clone, there was never anything like this.","TWN":"就算試著回想從複製人那裡得到的記憶，也從來沒有這樣過。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만, 그게 우리를 돕는 거랑 무슨 상관인데?","JPN":"でも、それと私たちを助けることに何の関係があるの？","ENG":"And what does that have to do with helping us?","TWN":"但是那跟幫助我們有什麼關係？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"간단해.","JPN":"簡単よ。","ENG":"Simple.","TWN":"很簡單。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"펠릭스의 부탁을 받고 온 너흴 도와주면 그 여자에게 빚을 안길뿐더러…….","JPN":"フェリックスに頼まれてここに来たお前たちを助けることで、あの女に借りを作れる。","ENG":"If I help you, who came at Felix's request, I saddle her with a debt, and...","TWN":"要是幫助受到緋莉克絲請求而來的妳們，不只是能讓那個女人對我有所虧欠……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"내가 본 미래는 대균열의 뿌리가 챔버를 삼키기 직전까지 네가 저항하는 모습이었거든.","JPN":"それに私が見た未来で、お前は大亀裂の根がチェンバーを飲み込む直前まで抵抗していたわ。","ENG":"In the future I saw, just before the Grand Dimension Crevice's roots swallowed Chamber, you were still resisting.","TWN":"而且我看到的未來，在大峽谷根部吞噬密室之前，妳都在抵抗。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"결국 네가 있는 곳이 격전지가 되는 셈이니, 내 안위를 위해 널 도와주는 거야.","JPN":"つまりお前がいる場所が激戦地になるってことだから、私は自分の身の安全のためにお前を助けるのよ。","ENG":"That means wherever you are becomes the battlefield. Helping you protects me.","TWN":"最後妳所在之處會成為激戰之地，我是為了自己的安危才幫妳。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"어때? 이정도면 납득이 가?","JPN":"これで納得できたかしら？","ENG":"Well. Does that convince you?","TWN":"怎麼樣？這樣能理解嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐, 되도 않는 대의명분을 들이미는 것보다는 낫네.","JPN":"ま、くだらない大義名分を押し付けられるよりはマシだね。","ENG":"Better than waving some lofty cause around.","TWN":"反正，總比說出一些荒唐的道義名分來得好。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그래서, 우릴 어떻게 돕는다는 건데?","JPN":"それで、どうやって私たちを助けるつもり？","ENG":"So how exactly are you planning to help us?","TWN":"所以妳要怎麼幫忙我們？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"모른 척하기는. 펠릭스가 너흴 시린그라드에 보낸 이유야 뻔하잖아?","JPN":"とぼけないで。フェリックスがお前たちをシリングラードに送った理由なんて、1つしかないでしょ。","ENG":"Don't play dumb. It's obvious why Felix sent you to Ciringrad.","TWN":"裝什麼蒜？緋莉克絲派妳們來錫林格勒的理由很明顯吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"마트료시카 연구소로 가는 인적 드문 루트를 알고 있으니, 너흰 따라오기만 하면 돼.","JPN":"マトリョシカ研究所に行ける、人通りの少ないルートを知ってるわ。黙ってついて来て。","ENG":"I know a little-used route to the Matryoshka Research Lab. You only need to follow me.","TWN":"我知道一條前往俄羅斯娃娃研究所，人跡罕至的路線，妳們只要跟著我走就好。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"LAUGH2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"거기 가서 뭐하는데?","JPN":"そこで何をしようっての？","ENG":"And what do we do there?","TWN":"去那裡幹什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"뭣…! 너, 설마 아무것도 모르는 거야?","JPN":"なっ……！　お前、まさか本当に何も知らないの？","ENG":"What...?! Do you seriously not know anything?","TWN":"什麼…！難道妳什麼都不知道嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그게… 서, 설명 도중에 레노어 언니가 왔거든요.","JPN":"その……せ、説明しようとしたところにレノアさんが来たから。","ENG":"W-well... th-that's because you showed up in the middle of my briefing, Ms. Lenore.","TWN":"那個…因為解、解釋到一半，蕾諾雅姐姐就來了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예니카는 지금 흐리멍덩, 아는 게 없는 상태예요.","JPN":"イェニカは今ぼけぼけ、知ってることが何もない状態なんです。","ENG":"Yanikka is out of it right now. She doesn't know anything.","TWN":"耶妮卡現在迷迷糊糊，一無所知。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저기-. 같은 말이라도 다르게 표현할 수 있지 않나요?","JPN":"あの～同じことでも、もうちょっとこう、言い方ってものがあるじゃないですか？","ENG":"Hey. You could phrase that more nicely, you know.","TWN":"那個–相同的意思也能用不同的方式表達吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하다못해 백치미 정도로 표현해주면 좋을 텐데.","JPN":"せめて天然とかにしてほしいなぁ。","ENG":"You could at least call it an airheaded charm.","TWN":"要是能用呆萌來表達就好了。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"칫. 그 여자는 대체 뭘 믿고 이런 녀석들을 보낸 거야?","JPN":"ちっ。あの女、こんな頼りのないやつらを送りやがって。","ENG":"Tch. What on earth made that woman send people like you?","TWN":"嘖，那個女人到底是憑什麼送這些傢伙過來？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래서? 펠릭스가 네게 뭘 부탁했는데?","JPN":"それで、フェリックスになんて頼まれてるわけ？","ENG":"So? What did Felix ask you to get?","TWN":"所以呢？緋莉克絲拜託妳什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"유, 율리아 님이 여기서 두 가지 물건을 가져와야 한다고 말하셨어요.","JPN":"ユ、ユリア様からは、ここで2つの物を手に入れるようにと言われています。","ENG":"M-Ms. Yulia said we need to bring back two items from here.","TWN":"茱、茱莉亞說要從這裡帶走兩樣物品。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"하, 하나는… 변질된 검은 이터니움.","JPN":"ひ、1つ目は……変質した黒いエタニウム。","ENG":"O-one is... the altered Dark Eternium.","TWN":"一、一個是…變質的黑色永恆之金。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그리고 나머지 하나는…….","JPN":"もう1つは……","ENG":"And the other is...","TWN":"然後另一個是……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"프로젝트 마트료시카의 적성 개체를 위한, <color=#ffd34c>청동 메모리코어</color>예요.","JPN":"プロジェクト・マトリョシカの適性個体のための、<color=#ffd34c>青銅メモリーコア</color>です。","ENG":"A <color=#ffd34c>Bronze Memory Core</color> for a Project Matryoshka compatible subject.","TWN":"為了俄羅斯娃娃計畫的適應性個體打造的<color=#ffd34c>青銅記憶核心</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"됐어. 이제 연구소 안으로 들어가면 돼.","JPN":"着いたわ。あとは研究所に入るだけよ。","ENG":"Okay. Then we head inside the lab now.","TWN":"好了，現在可以進去研究所了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그러니 이상한데 숨지 말고 나와. 보는 내가 부끄럽다고.","JPN":"だから変なとこに隠れてないで出てきなさいって。見てるこっちが恥ずかしいわ。","ENG":"So stop hiding in weird spots and come out. I'm embarrassed for you.","TWN":"所以雖然很奇怪，但不要躲躲藏藏，出來吧，我看著也覺得難為情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐래. 너야 자존심 내려놓고 노예 신세를 자처했지만, 우린 들키면 곤란한 입장이거든?","JPN":"ふん、あなたはプライドなんか捨てて奴隷を買って出たけど、私たちはバレたら困るんだよ。","ENG":"Says the one who dropped her pride and chose to play slave. We can't afford to get spotted.","TWN":"妳在說什麼？雖然妳是放下自尊以奴隸身分自居，但我們要是被發現可就麻煩了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"곧 닥쳐올 일 정도는 알 수 있다고 말했잖아! 그리고 누가 노예야?","JPN":"近い未来はわかるって言ったでしょ！　あと、誰が奴隷よ？","ENG":"I told you I can see what's about to happen. And who are you calling a slave?","TWN":"我不是說過能知道馬上要到來的事嗎！而且誰是奴隸？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그 출입 카드… 합의체에서 사용하는 게 아닌 시린그라드에서 가공한 물건이네요.","JPN":"そ、そのカードキー……合意体で使用されているものじゃなくて、シリングラードで独自に加工したものですね。","ENG":"Th-that access card... it's not Northern Union-issued, but was machined here in Ciringrad.","TWN":"那、那個通行證…不是和議會使用的，而是錫林格勒加工的物品。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"레노어 언니가 그걸 어떻게 갖고 있는 건가요?","JPN":"どうしてレノアさんがそれを持ってるんですか？","ENG":"How do you even have that, Ms. Lenore?","TWN":"蕾諾雅姐姐手上怎麼會有那個？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"흥. 최신 프로젝트의 부산물을 시린그라드에서 독자적으로 분석할 수 있겠어?","JPN":"ふん。最新プロジェクトの副産物をシリングラードが独自に分析できるわけがないでしょ。","ENG":"Hmph. You think Ciringrad can independently analyze byproducts from our latest projects?","TWN":"哼，難不成錫林格勒能獨自分析最新計畫的副產物嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"어차피 놔둬봤자 쓰레기 섬이니, 밑져야 본전으로 내게 맡긴 거야.","JPN":"どうせ放置しておいてもただのゴミ捨て場だから、ダメ元で私に預けたのよ。","ENG":"It's junk otherwise, so they dumped it on me as a nothing-to-lose trial.","TWN":"反正放著也會是座垃圾島，不如交給我還不會虧本。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"LAUGH2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"쓰, 쓰레기 섬이요?","JPN":"ゴ、ゴミ捨て場？","ENG":"A-a trash island?","TWN":"垃、垃圾島？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"부서진 골리앗과 그렌델의 파편이나 합의체에서 폐기한 실험체들.","JPN":"壊れたゴリアテとグレンデルの破片とか、合意体が破棄した実験体。","ENG":"Shattered Goliath and Grendel fragments, and test subjects the Northern Union scrapped.","TWN":"一些破裂的歌利亞和格蘭德的碎片，跟和議會廢棄的實驗體。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그리고 검은 이터니움 같은 애물단지들을 모아 놓았다는 소리야.","JPN":"そして黒いエタニウムみたいに、厄介なものが集まってるってことよ。","ENG":"Plus dead weight like Dark Eternium.","TWN":"還有像是黑色永恆之金這種珍貴的物品聚集的意思。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"재활용할 수만 있다면 마을에 큰 보탬이 될 테니, 다른 곳에 처분하기도 애매했겠지.","JPN":"リサイクル方法さえ見つかれば村には大いに役立つものだから、別の場所に捨てるのはもったいなかったんでしょう。","ENG":"If any of it can be recycled, it helps the village a lot, so they couldn't exactly dump it elsewhere.","TWN":"只要可以再利用的話，應該會對村子有很大的幫助，所以也不適合賣到其他地方。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아, 갈림길.","JPN":"あ、分かれ道。","ENG":"Ah, a fork in the path.","TWN":"啊，岔路。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L25_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 어디로 가면 돼?","JPN":"モ、モコ。今度はどっちに行けばいいの？","ENG":"F-Fluffox. Which way do we go?","TWN":"福、福實，要往哪裡走？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"오, 오른쪽…!","JPN":"み、右……！","ENG":"R-right...!","TWN":"右、右邊…！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"아니, 왼쪽으로 가자.","JPN":"いいえ、左に行きましょう。","ENG":"No. We go left.","TWN":"不，往左邊走吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L33_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실이 거짓말 안 했어요.","JPN":"モ、モコは嘘つきません。","ENG":"F-Fluffox doesn't lie.","TWN":"福、福實沒有說謊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"안전한 건 오른쪽이 맞아. 왼쪽 구역은 보안 프로세스의 오작동 문제로 출입 금지거든.","JPN":"安全なのは右で合ってるわ。左のエリアはセキュリティプロセスの不具合で、立ち入り禁止なのよね。","ENG":"Right is the safer route. The left sector is off-limits due to a malfunction in the security process.","TWN":"安全的路線是右邊沒錯，左邊區域因為保安程序故障的問題，禁止進入。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하지만 오른쪽은 돌아가는 만큼 시간이 소모돼.","JPN":"でも、右は回り道をする分時間がかかる。","ENG":"But the right path takes more time.","TWN":"但是右邊要繞路會消耗時間。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너희도 시간을 끌어서 좋을 건 없잖아?","JPN":"お前たちだって、ここで時間をかけたくないでしょう？","ENG":"Dragging this out doesn't help you either, does it?","TWN":"拖延時間對妳們來說也沒好處吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯哼……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어떻게 생각해요, 나탈리아? 저 여자. 신뢰할 수 있을까요?","JPN":"ナタリア、どう思いますか？　あの女、信じてもいいんでしょうか？","ENG":"What do you think, Natalia? Can we trust her?","TWN":"那塔利亞，妳覺得怎麼樣？可以信任那個女人嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"레, 레노어 언니가 여기 있다는 걸 율리아 님이 모르실 리는 없어요.","JPN":"レ、レノアさんがここにいるのを、ユリア様が知らないわけはありません。","ENG":"There's no way Ms. Yulia doesn't know Ms. Lenore is here.","TWN":"茱、茱莉亞不可能不知道蕾諾雅姐姐在這裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그러니까 어, 언니의 행동도 계획의 일부라고 생각해요.","JPN":"だから、レ、レノアさんの行動も、計画のうちだと思います。","ENG":"S-so I think her actions are part of the plan.","TWN":"所以我認為姐、姐姐的行動也是計畫的一部分。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"지나친 공상인 것 같지만… 뭐, 수틀리면 저 여자 머리채라도 붙잡으면 되겠죠.","JPN":"それはさすがに考えすぎだと思うけど……まあ、いざとなったら髪の毛引っ掴んで言うこと聞かせますか。","ENG":"Sounds a little far-fetched, but if it goes south I can always grab her by the hair.","TWN":"雖然感覺是過度空想…但反正，要是不如意的話，抓住那個女人的頭髮就好了吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"시간을 끌어서 좋을 게 없다는 건 사실이니까요.","JPN":"時間をかけたくないのは事実ですからね。","ENG":"And she is right that we have nothing to gain by stalling.","TWN":"畢竟拖延時間的確沒什麼好處。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"참고로 안에 있는 병기들은 섬멸모드가 가동된 상태에서 강제 셧다운 된 상태야.","JPN":"ちなみに、中にある兵器は殲滅モードが稼働した状態で強制的にシャットダウンされているわ。","ENG":"For the record, the weapons inside were forced into shutdown while in annihilation mode.","TWN":"順帶一提，裡面的兵器都是在殲滅模式啟動的狀態下被強制關閉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"즉, 프로그램을 재부팅하면 합의체 병기들이 우릴 공격한단 소리지.","JPN":"つまり、プログラムが再起動したら合意体の兵器に攻撃されるってことよ。","ENG":"Which means if we reboot the programs, the Northern Union weapons will attack us.","TWN":"也就是說，重新啟動程式的話，那些和議會兵器就會攻擊我們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"준비됐어?","JPN":"覚悟はいい？","ENG":"Ready?","TWN":"準備好了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"PRIDE2"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START2"},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그깟 고물 상대하는데 준비는 무슨.","JPN":"ただの鉄くず相手に、覚悟なんていらないよ。","ENG":"I don't need to get ready to take on a pile of scrap.","TWN":"對付區區廢鐵還要準備什麼？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"시간 없으니까, 후딱 끝내자.","JPN":"時間がないから、さっさと終わらせよう。","ENG":"We're short on time, so let's wrap this up fast.","TWN":"沒時間了，我們速戰速決吧。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_CHAINSAW_START"}]`);export{e as default};